class Solution:
    def countOfPairs(self, nums):
        MOD = 10**9 + 7
        n = len(nums)
        if n == 1:
            return nums[0] + 1
        # dp[v] = ways for arr1[i] == v, use prefix sums
        dp = [1] * (nums[0] + 1)
        for i in range(1, n):
            # prefix[v] = sum(dp[0..v])
            prefix = [0] * (nums[i-1] + 2)
            for v in range(nums[i-1] + 1):
                prefix[v+1] = (prefix[v] + dp[v]) % MOD
            new_dp = [0] * (nums[i] + 1)
            for v in range(nums[i] + 1):
                # arr1[i-1] <= min(v, nums[i-1]-(nums[i]-v)) = min(v, nums[i-1]-nums[i]+v)
                upper = min(v, nums[i-1] - nums[i] + v)
                if upper < 0:
                    continue
                upper = min(upper, nums[i-1])
                new_dp[v] = prefix[upper + 1]
            dp = new_dp
        return sum(dp) % MOD

