var countOfPairs = function(nums) {
    const MOD = BigInt(10**9 + 7);
    const n = nums.length;
    if (n === 1) return (nums[0] + 1) % (10**9 + 7);
    let dp = new Array(nums[0] + 1).fill(1n);
    for (let i = 1; i < n; i++) {
        const prefix = new Array(nums[i-1] + 2).fill(0n);
        for (let v = 0; v <= nums[i-1]; v++) {
            prefix[v+1] = (prefix[v] + dp[v]) % MOD;
        }
        const newDp = new Array(nums[i] + 1).fill(0n);
        for (let v = 0; v <= nums[i]; v++) {
            let upper = Math.min(v, nums[i-1] - nums[i] + v);
            if (upper < 0) continue;
            upper = Math.min(upper, nums[i-1]);
            newDp[v] = prefix[upper + 1];
        }
        dp = newDp;
    }
    let ans = 0n;
    for (const x of dp) ans = (ans + x) % MOD;
    return Number(ans);
};
